**Unit Tests for `zip_dicts()`**

```python
import pytest
from typing import Any


def zip_dicts(*dicts) -> dict:
    keys = set().union(*dicts)
    return {k: [d.get(k) for d in dicts] for k in keys}


# ====================== Happy Path ======================


def test_zip_dicts_two_simple_dicts():
    d1 = {"a": 1, "b": 2}
    d2 = {"b": 20, "c": 30}
    result = zip_dicts(d1, d2)

    assert result == {
        "a": [1, None],
        "b": [2, 20],
        "c": [None, 30],
    }


def test_zip_dicts_three_dicts():
    d1 = {"name": "Alice", "age": 30}
    d2 = {"name": "Bob", "city": "NYC"}
    d3 = {"age": 25, "city": "London"}

    result = zip_dicts(d1, d2, d3)

    assert result == {
        "name": ["Alice", "Bob", None],
        "age": [30, None, 25],
        "city": [None, "NYC", "London"],
    }


def test_zip_dicts_with_empty_dicts():
    d1 = {"x": 10}
    d2 = {}
    d3 = {"x": 30, "y": 40}

    result = zip_dicts(d1, d2, d3)

    assert result == {
        "x": [10, None, 30],
        "y": [None, None, 40],
    }


def test_zip_dicts_all_identical_keys():
    d1 = {"a": 1}
    d2 = {"a": 2}
    d3 = {"a": 3}

    assert zip_dicts(d1, d2, d3) == {"a": [1, 2, 3]}


def test_zip_dicts_with_none_and_falsey_values():
    d1 = {"a": None, "b": False, "c": 0}
    d2 = {"a": 1, "b": 0, "c": False}

    assert zip_dicts(d1, d2) == {
        "a": [None, 1],
        "b": [False, 0],
        "c": [0, False],
    }


# ====================== Edge Cases ======================


def test_zip_dicts_no_arguments():
    result = zip_dicts()
    assert result == {}


def test_zip_dicts_single_dict():
    d = {"a": 1, "b": 2}
    result = zip_dicts(d)

    assert result == {
        "a": [1],
        "b": [2],
    }


def test_zip_dicts_empty_dict_only():
    assert zip_dicts({}) == {}
    assert zip_dicts({}, {}, {}) == {}


def test_zip_dicts_with_duplicate_keys_across_dicts():
    # This is normal behavior — keys are unioned
    d1 = {"x": 1, "y": 2}
    d2 = {"y": 20, "z": 3}
    d3 = {"x": 10, "z": 30}

    assert zip_dicts(d1, d2, d3) == {
        "x": [1, None, 10],
        "y": [2, 20, None],
        "z": [None, 3, 30],
    }


# ====================== Error Cases ======================


def test_zip_dicts_with_non_dict_argument_raises_type_error():
    with pytest.raises(TypeError):
        zip_dicts({"a": 1}, ["not", "a", "dict"])

    with pytest.raises(TypeError):
        zip_dicts({"a": 1}, 123)

    with pytest.raises(TypeError):
        zip_dicts({"a": 1}, None)


def test_zip_dicts_mixed_valid_and_invalid_raises_type_error():
    with pytest.raises(TypeError):
        zip_dicts({"a": 1}, {"b": 2}, "invalid")


# ====================== Additional Robustness ======================


def test_zip_dicts_preserves_order_of_input_dicts_in_lists():
    """The order of values in each list should match the order of input dicts."""
    d1 = {"a": "first"}
    d2 = {"a": "second"}
    d3 = {"a": "third"}

    result = zip_dicts(d1, d2, d3)
    assert result["a"] == ["first", "second", "third"]
